    for article in articles:
        try:
            published_time = pd.to_datetime(article['published_time'])
            published_time_tz = published_time.astimezone(pytz.timezone(timezone))
            article['published_hour'] = published_time_tz.hour
        except Exception as e:
            raise ValueError("Invalid 'published_time' format.") from e

    df = pd.DataFrame(articles)

    result_df = df.groupby('category')['published_hour'].agg(['count', 'mean', 'min', 'max']).reset_index()

    result_df.set_index('category', inplace=True)

    return result_df

